def discover_new_events(self):
    """메가박스 신규 이벤트를 탐색하여 저장합니다."""
    logger.info("Megabox auto-discovery started...")
    data = self.fetch_events(page=1)
    if data and "eventList" in data:
        found = 0
        for item in data["eventList"]:
            event_id = str(item.get("eventNo"))
            event = self.session.query(Event).filter_by(EventID=event_id).first()
            if not event:
                self.save_event(item)
                found += 1
        logger.info(f"Megabox discovery finished. Found {found} new events.")

